def _sort_palette_colors(im, sort_palette):
    """
    Reorders the palette of a "P" mode image, remapping pixel values so
    that the image is displayed unchanged. Used by :py:meth:`~PIL.Image.Image.quantize`
    to implement its ``sort_palette`` argument.

    :param im: A "P" mode :py:class:`~PIL.Image.Image` object.
    :param sort_palette: ``"brightness"`` to sort colors by perceived brightness,
       or ``"rgb"`` to sort colors by their (r, g, b) value.
    :returns: A new :py:class:`~PIL.Image.Image` object.
    """
    if sort_palette not in ("brightness", "rgb"):
        raise ValueError("sort_palette must be 'brightness' or 'rgb'")

    mode = im.im.getpalettemode()
    channels = len(mode)
    palette = im.im.getpalette(mode, mode)
    colors = [
        tuple(palette[i : i + channels]) for i in range(0, len(palette), channels)
    ]

    if sort_palette == "brightness":
        def sort_key(i):
            r, g, b = colors[i][:3]
            return 0.299 * r + 0.587 * g + 0.114 * b

    else:
        def sort_key(i):
            return colors[i]

    dest_map = sorted(range(len(colors)), key=sort_key)
    return im.remap_palette(dest_map)


